mapper.update:
UPDATE FWK_WAS_PROPERTY
SET CUR_VERSION = NVL(CUR_VERSION, 0) + 1
WHERE INSTANCE_ID = #{instanceId}
  AND PROPERTY_GROUP_ID = #{propertyGroupId}

mapper.delete:
DELETE FROM FWK_WAS_PROPERTY
WHERE INSTANCE_ID = #{instanceId}
  AND PROPERTY_GROUP_ID = #{propertyGroupId}

mapper.select:
SELECT MAX(VERSION)
FROM FWK_WAS_PROPERTY_HISTORY
WHERE INSTANCE_ID = #{instanceId}
  AND PROPERTY_GROUP_ID = #{propertyGroupId}

mapper.insert:
INSERT INTO FWK_WAS_PROPERTY_HISTORY ( INSTANCE_ID, PROPERTY_GROUP_ID, PROPERTY_ID, VERSION, PROPERTY_VALUE, PROPERTY_DESC, REASON, LAST_UPDATE_USER_ID, LAST_UPDATE_DTIME ) SELECT A.* FROM (
SELECT #{item.instanceId}, #{item.propertyGroupId}, #{item.propertyId}, #{item.version}, #{item.propertyValue, jdbcType=VARCHAR}, #{item.propertyDesc, jdbcType=VARCHAR}, #{item.reason, jdbcType=VARCHAR}, #{item.lastUpdateUserId}, #{item.lastUpdateDtime} FROM DUAL
) A

INSERT INTO FWK_WAS_PROPERTY ( INSTANCE_ID, PROPERTY_GROUP_ID, PROPERTY_ID, PROPERTY_VALUE, PROPERTY_DESC, CUR_VERSION ) SELECT A.* FROM (
SELECT #{item.instanceId}, #{item.propertyGroupId}, #{item.propertyId}, #{item.propertyValue, jdbcType=VARCHAR}, #{item.propertyDesc, jdbcType=VARCHAR}, #{item.version, jdbcType=NUMERIC} FROM DUAL
) A
